  "activeProvider": "xai",
  "providers": [
    {
      "id": "openai",
      "configured": true,
      "transports": ["gateway-relay"],
      "brains": ["none"],
      "defaultModel": "gpt-4o-transcribe"
    }
  ]
}
```

